RedArmyBases.init_data = function()
    for _, town_type in pairs(RedArmyBases.types) do
        local weight = {}
        local dataset = RedArmyBases[town_type]
        assert(dataset.data, 'missing town data')
        for idx, dataset in pairs(RedArmyBases[town_type].data) do
            assert(dataset.weight, "missing weight data")
            for i = 1, dataset.weight, 1 do
                table_insert(weight, idx)
            end
        end
        dataset.weight = weight
        dataset.weight_size = #weight
        dataset.data_size = #dataset.data
        if DEBUG_MODE then
            print(town_type.." data:")
            print(serpent.block(dataset))
        end
    end
end
RedArmyBases.init_data()

RedArmyBases.get_town = function(town_type)
    if not RedArmyBases[town_type] then
        return
    end
    local town_building_data = RedArmyBases[town_type]
    local town_data = town_building_data.data[math_random(1, town_building_data.data_size)].buildings
    local base_width =  town_building_data.base_width
    return town_data, base_width 
end

return RedArmyBases